import type { Metadata } from "next";
import ProductionOrder from "./ProductionOrder";

export const metadata: Metadata = {
  title: "生産指示 / 工程進捗 (MES) | ぐんじょう",
  description:
    "製造現場の生産指示・工程進捗画面。製造指図番号 / 品番・品名 / 指示数量 / 納期 / 着手日 / 製造ライン / 担当とステータス（未着手 / 製造中 / 完了 / 保留）を表示。工程ルート（材料投入 → 加工 → 組立 → 検査 → 梱包）を各工程の設備・作業者・状態（完了 / 仕掛 / 待ち / 故障）・良品数 / 不良数・開始/完了時刻つきで追跡し、現在の工程を強調。現工程の実績入力（良品数 / 不良数）が完成数・仕掛数・良品率にライブで反映。ライン稼働状況（稼働中 / 段取り替え / チョコ停 / 故障停止）と稼働率（OEE）ゲージ、進捗サマリ（指示数量 / 完成数 / 仕掛数 / 不良数 / 良品率 / 進捗率 / 計画比）、不良項目別の不良集計（パレート）と不良率しきい値警告、製造完了報告 / 作業指示書印刷 / 進捗レポートを備えた班長向けのショップフロアツールです。",
};

export default function ProductionOrderPage() {
  return <ProductionOrder />;
}

// 生産指示 / 工程進捗 — shop-floor MES domain model + derivations.
// All quantities are integers (個). Times are "HH:MM".

export type ProcessStatus = "waiting" | "wip" | "completed" | "down" | "delayed";
export type LineStatus = "running" | "setup" | "chokotei" | "fault";
export type OrderStatus = "not-started" | "in-progress" | "completed" | "hold";

/** One 工程 (process step) in the route. */
export interface ProcessStep {
  id: string;
  /** 工程名 e.g. 材料投入 / 切削加工 */
  name: string;
  /** 設備 / 号機 */
  equipment: string;
  /** 担当作業者 */
  operator: string;
  status: ProcessStatus;
  /** 投入数 (qty fed into this process). */
  input: number;
  /** 良品数 produced by this process. */
  good: number;
  /** 不良数 produced by this process. */
  defect: number;
  startTime?: string;
  endTime?: string;
}

export interface DefectReason {
  code: string;
  /** 不良項目 e.g. キズ / 寸法外れ */
  label: string;
  count: number;
}

export interface ProductionOrder {
  /** 製造指図番号 */
  orderNo: string;
  /** 品番 */
  partNo: string;
  /** 品名 */
  partName: string;
  /** 指示数量 */
  orderQty: number;
  /** 納期 */
  dueDate: string;
  /** 着手日 */
  startDate: string;
  /** 製造ライン */
  line: string;
  /** 班長 / 担当 */
  supervisor: string;
  status: OrderStatus;
  lineStatus: LineStatus;
  /** 計画稼働時間(分) — for 稼働率. */
  plannedRuntimeMin: number;
  /** 実稼働時間(分). */
  actualRuntimeMin: number;
  /** この時刻までに完成しているべき計画完成数 (for 計画比). */
  plannedDoneByNow: number;
  /** 不良率しきい値 (注意 / 超過) as fractions. */
  defectRateWarn: number;
  defectRateCritical: number;
  steps: ProcessStep[];
  defects: DefectReason[];
}

// ── Derivations (single source of truth for all reconciled numbers) ──────────

/** 仕掛数 for a process = 投入 − 完成(良品) − 不良 (cannot go below 0). */
export function stepWip(s: ProcessStep): number {
  return Math.max(0, s.input - s.good - s.defect);
}

/** 良品率 of a process = 良品 / (良品 + 不良). Returns null when nothing produced. */
export function stepYield(s: ProcessStep): number | null {
  const produced = s.good + s.defect;
  return produced > 0 ? s.good / produced : null;
}

/** Index of the current (仕掛) process, else first 待ち, else last completed. */
export function currentStepIndex(steps: ProcessStep[]): number {
  const wip = steps.findIndex((s) => s.status === "wip" || s.status === "down");
  if (wip !== -1) return wip;
  const waiting = steps.findIndex((s) => s.status === "waiting");
  if (waiting !== -1) return waiting;
  return steps.length - 1;
}

export interface OrderTotals {
  orderQty: number;
  /** 投入数 = 第1工程に投入した総数 (units started into the line). */
  started: number;
  /** 完成数 = 良品 out of the FINAL process (units that cleared the whole route). */
  finished: number;
  /** 仕掛数 = 投入 − 完成 − 累計不良 (units in-process between first and last step). */
  wip: number;
  /** 累計不良数 = sum of all process defects (== defect-reason tally). */
  totalDefect: number;
  /** 良品率 (直行率) = (投入 − 累計不良) / 投入. fraction of started units that are non-defective. */
  yieldRate: number | null;
  /** 進捗率 = 完成数 / 指示数量. */
  progressRate: number;
  /** 計画比 = 完成数 − 計画完成数 (signed; + = ahead/先行). */
  planVariance: number;
  /** 稼働率 = 実稼働時間 / 計画稼働時間. */
  operatingRate: number;
}

/**
 * Roll the per-process 実績 up to the order total.
 * - 投入(started) = first process input (everything fed into the line).
 * - 完成(finished) = good output of the FINAL process (units that cleared the whole route).
 * - 累計不良(totalDefect) = sum of every process's defects (reconciles with the tally).
 * - 仕掛(wip) = 投入 − 完成 − 累計不良 (still moving through intermediate steps).
 * - 良品率(直行率) = (投入 − 累計不良) / 投入 — meaningful in every state, unlike a
 *   finished-only ratio that reads 0% mid-route.
 */
export function computeTotals(order: ProductionOrder): OrderTotals {
  const steps = order.steps;
  const first = steps[0];
  const last = steps[steps.length - 1];
  const started = first ? first.input : 0;
  const finished = last ? last.good : 0;
  const totalDefect = steps.reduce((sum, s) => sum + s.defect, 0);
  const wip = Math.max(0, started - finished - totalDefect);
  const yieldRate = started > 0 ? (started - totalDefect) / started : null;
  const progressRate = order.orderQty > 0 ? finished / order.orderQty : 0;
  const planVariance = finished - order.plannedDoneByNow;
  const operatingRate =
    order.plannedRuntimeMin > 0 ? order.actualRuntimeMin / order.plannedRuntimeMin : 0;
  return {
    orderQty: order.orderQty,
    started,
    finished,
    wip,
    totalDefect,
    yieldRate,
    progressRate,
    planVariance,
    operatingRate,
  };
}

/** 不良率 = 累計不良 / 投入数 (defects per unit started). 0 when nothing started. */
export function orderDefectRate(t: OrderTotals): number {
  return t.started > 0 ? t.totalDefect / t.started : 0;
}

