  formatPercent,
  type BadgeProps,
  type RouteStopItem,
  type RouteStopStatus,
  type MeterTone,
  type ChartColor,
} from "@gunjo/ui";

import {
  ALL_ORDERS,
  LINE_STATUS_LABEL,
  ORDER_STATUS_LABEL,
  PROCESS_STATUS_LABEL,
  computeTotals,
  currentStepIndex,
  orderDefectRate,
  stepWip,
  stepYield,
  type LineStatus,
  type OrderStatus,
  type ProcessStatus,
  type ProcessStep,
  type ProductionOrder,
} from "./data";

const nf = (n: number) => formatNumber(n);
const pf = (r: number | null, digits = 1) =>
  r === null ? "—" : formatPercent(r, { maximumFractionDigits: digits });

// ── status → semantic mappers ────────────────────────────────────────────────

const ORDER_STATUS_BADGE: Record<OrderStatus, BadgeProps["variant"]> = {
  "not-started": "secondary",
  "in-progress": "info",
  completed: "success",
  hold: "warning",
};

const LINE_STATUS_BADGE: Record<LineStatus, BadgeProps["variant"]> = {
  running: "success",
  setup: "warning",
  chokotei: "warning",
  fault: "destructive",
};

const LINE_STATUS_ICON: Record<LineStatus, React.ComponentType<{ className?: string }>> = {
  running: IconBolt,
  setup: IconAdjustments,
  chokotei: IconClock,
  fault: IconTool,
};

// 工程ルート status → RouteStops status. (manufacturing semantics over delivery)
const PROCESS_TO_ROUTE: Record<ProcessStatus, RouteStopStatus> = {
  waiting: "pending",
  wip: "current",
  completed: "completed",
  down: "failed",
  delayed: "delayed",
};

// RouteStops ships delivery-flavoured labels ("配送中"/"不在"); relabel for the floor.
const ROUTE_STATUS_LABELS: Partial<Record<RouteStopStatus, string>> = {
  pending: "待ち",
  current: "仕掛",
  completed: "完了",
  failed: "故障停止",
  delayed: "遅延",
};

/** higher-is-better tone for yield / OEE-style ratios against a target. */
function rateTone(rate: number, target: number, floor: number): MeterTone {
  if (rate >= target) return "success";
  if (rate >= floor) return "warning";
  return "destructive";
}

function rateChartColor(rate: number, target: number, floor: number): ChartColor {
  if (rate >= target) return "success";
  if (rate >= floor) return "warning";
  return "destructive";
}

export default function ProductionOrder() {
  const [orderId, setOrderId] = React.useState(ALL_ORDERS[0].orderNo);
  const baseOrder = ALL_ORDERS.find((o) => o.orderNo === orderId) ?? ALL_ORDERS[0];

  // Live per-order step state so 実績入力 rolls up without mutating the seed.
  const [stepStateByOrder, setStepStateByOrder] = React.useState<
    Record<string, ProcessStep[]>
  >({});
  // Line status is operator-mutable on the floor.
  const [lineStatusByOrder, setLineStatusByOrder] = React.useState<
    Record<string, LineStatus>
  >({});

  const steps = stepStateByOrder[orderId] ?? baseOrder.steps;
  const lineStatus = lineStatusByOrder[orderId] ?? baseOrder.lineStatus;
  const order: ProductionOrder = React.useMemo(
    () => ({ ...baseOrder, steps, lineStatus }),
    [baseOrder, steps, lineStatus]
  );

  const curIdx = currentStepIndex(steps);
  const curStep = steps[curIdx];
  const totals = computeTotals(order);
  const defectRate = orderDefectRate(totals);
  const isClosed = order.status === "completed";
  // Defect-rate nags only matter for a live order — a closed order shouldn't warn.
  const defectOver = !isClosed && defectRate >= order.defectRateCritical;
  const defectWarn = !isClosed && !defectOver && defectRate >= order.defectRateWarn;

  // Defect tally reconciliation: reasons should sum to 累計不良.
  const reasonSum = order.defects.reduce((s, d) => s + d.count, 0);
  const defectsSorted = [...order.defects].sort((a, b) => b.count - a.count);
  const defectMax = defectsSorted[0]?.count ?? 0;

  const updateCurrentStep = (patch: Partial<ProcessStep>) => {
    setStepStateByOrder((prev) => {
      const cur = prev[orderId] ?? baseOrder.steps;
      const next = cur.map((s, i) => (i === curIdx ? { ...s, ...patch } : s));
      return { ...prev, [orderId]: next };
    });
  };

  const setStepStatus = (idx: number, status: ProcessStatus) => {
    setStepStateByOrder((prev) => {
      const cur = prev[orderId] ?? baseOrder.steps;
      const next = cur.map((s, i) => (i === idx ? { ...s, status } : s));
      return { ...prev, [orderId]: next };
    });
  };

  // ── 工程ルート → RouteStops items ──────────────────────────────────────────
  const routeStops: RouteStopItem[] = steps.map((s, i) => {
    const y = stepYield(s);
    const produced = s.good + s.defect;
    const isCurrent = i === curIdx && order.status !== "completed";
    return {
      id: s.id,
      seq: i + 1,
      status: isCurrent ? "current" : PROCESS_TO_ROUTE[s.status],
      title: s.name,
      description: `${s.equipment} ・ 作業者 ${s.operator}`,
      meta:
        produced > 0 ? (
          <span className="inline-flex flex-wrap items-center gap-x-2 gap-y-0.5">
            <span className="text-success-strong">良 {nf(s.good)}</span>
            <span className={s.defect > 0 ? "text-destructive" : "text-muted-foreground"}>
              不良 {nf(s.defect)}
            </span>
            {y !== null ? (
              <span className="text-muted-foreground">良品率 {pf(y)}</span>
            ) : null}
          </span>
        ) : undefined,
      plannedTime: s.startTime,
      actualTime: s.endTime,
      actions:
        order.status === "completed" ? undefined : i === curIdx ? (
          s.status === "wip" || s.status === "down" ? (
            <Button
              size="sm"
              variant="success"
              onClick={() => setStepStatus(i, "completed")}
            >
              <IconCheck className="h-4 w-4" />
              工程完了
            </Button>
          ) : s.status === "waiting" ? (
            <Button size="sm" variant="primary" onClick={() => setStepStatus(i, "wip")}>
              <IconPlayerPlay className="h-4 w-4" />
              着手
            </Button>
          ) : undefined
        ) : undefined,
    };
  });

  const LineIcon = LINE_STATUS_ICON[order.lineStatus];

  // OEE-ish 稼働率 (実稼働 / 計画稼働)
  const oee = totals.operatingRate;
  const oeeColor = rateChartColor(oee, 0.85, 0.6);
  // 良品率 target band
  const yieldTone: MeterTone =
    totals.yieldRate === null ? "muted" : rateTone(totals.yieldRate, 0.98, 0.95);

  return (
    <main className="mx-auto w-full max-w-screen-xl px-4 py-6 sm:px-6 lg:px-8">
      {/* ── Page header ─────────────────────────────────────────────────── */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
        <div className="flex flex-col gap-1">
          <div className="flex items-center gap-2 text-sm text-muted-foreground">
            <IconBuildingFactory2 className="h-4 w-4" aria-hidden="true" />
            生産指示 / 工程進捗 (MES)
          </div>
          <h1 className="text-2xl font-bold tracking-tight">製造指図 {order.orderNo}</h1>
        </div>
        <div className="w-full sm:w-72">
          <Select
            label="製造指図を切り替え"
            value={orderId}
            onChange={(e) => setOrderId(e.target.value)}
          >
            {ALL_ORDERS.map((o) => (
              <option key={o.orderNo} value={o.orderNo}>
                {o.orderNo}・{o.partName}（{ORDER_STATUS_LABEL[o.status]}）
              </option>
            ))}
          </Select>
        </div>
      </div>

      <Separator className="my-5" />

      {/* ── 製造指示ヘッダ ───────────────────────────────────────────────── */}
      <Card>
        <CardHeader className="gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div className="space-y-1.5">
            <div className="flex flex-wrap items-center gap-2">
              <CardTitle as="h2" className="text-xl">
                {order.partName}
              </CardTitle>
              <Badge variant={ORDER_STATUS_BADGE[order.status]}>
                {ORDER_STATUS_LABEL[order.status]}
              </Badge>
            </div>
            <CardDescription>
              品番 {order.partNo}・指示数量 {nf(order.orderQty)} 個
            </CardDescription>
          </div>
          {/* ライン状態 — icon + text, never colour alone */}
          <Badge
            variant={LINE_STATUS_BADGE[order.lineStatus]}
            className="h-7 gap-1.5 px-3 text-sm"
          >
            <LineIcon className="h-4 w-4" aria-hidden="true" />
            ライン: {LINE_STATUS_LABEL[order.lineStatus]}
          </Badge>
        </CardHeader>
        <CardContent>
          <MetadataList
            layout="horizontal"
            items={[
              { label: "製造指図番号", value: order.orderNo },
              { label: "品番 / 品名", value: `${order.partNo} / ${order.partName}` },
              { label: "指示数量", value: `${nf(order.orderQty)} 個` },
              { label: "納期", value: order.dueDate },
              { label: "着手日", value: order.startDate },
              { label: "製造ライン", value: order.line },
              { label: "担当", value: order.supervisor },
            ]}
          />
        </CardContent>
      </Card>

      {/* ── 不良率超過 / 故障 warning banners ─────────────────────────────── */}
      {(defectOver || order.lineStatus === "fault") && (
        <Alert variant="destructive" className="mt-4">
          <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
          <AlertTitle as="h2">要対応: 製造を確認してください</AlertTitle>
          <AlertDescription>
            {defectOver && (
              <span className="block">
                不良率 {pf(defectRate, 2)} が許容上限 {pf(order.defectRateCritical, 0)} を超過しています。原因を特定し、工程を止めて調査してください。
              </span>
            )}
            {order.lineStatus === "fault" && (
              <span className="block">
                {order.line} が故障停止中です。保全に連絡してください。
              </span>
            )}
          </AlertDescription>
        </Alert>
      )}
      {defectWarn && !defectOver && order.lineStatus !== "fault" && (
        <Alert variant="warning" className="mt-4">
          <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
          <AlertTitle as="h2">不良率 注意</AlertTitle>
          <AlertDescription>
            不良率 {pf(defectRate, 2)} が注意水準 {pf(order.defectRateWarn, 0)} を超えています。傾向を監視してください。
          </AlertDescription>
        </Alert>
      )}

      {/* ── 進捗サマリ KPIs ───────────────────────────────────────────────── */}
      <section aria-labelledby="kpi-heading" className="mt-6">
        <h2 id="kpi-heading" className="mb-3 flex items-center gap-2 text-lg font-semibold">
          <IconReportAnalytics className="h-5 w-5" aria-hidden="true" />
          進捗サマリ
        </h2>
        <div className="grid grid-cols-2 gap-3 md:grid-cols-3 lg:grid-cols-6">
          <Statistic label="指示数量" value={`${nf(totals.orderQty)} 個`} />
          <Statistic
            label="完成数"
            value={`${nf(totals.finished)} 個`}
            trend={totals.finished > 0 ? "up" : "flat"}
            tone="positive"
            change={`進捗 ${pf(totals.progressRate)}`}
          />
          <Statistic label="仕掛数" value={`${nf(totals.wip)} 個`} hint="投入 − 完成 − 不良" />
          <Statistic
            label="不良数"
            value={`${nf(totals.totalDefect)} 個`}
            trend={totals.totalDefect > 0 ? "down" : "flat"}
            tone={defectOver ? "negative" : "neutral"}
            change={`不良率 ${pf(defectRate, 2)}`}
          />
          <Statistic
            label="良品率"
            value={pf(totals.yieldRate)}
            tone={
              totals.yieldRate !== null && totals.yieldRate >= 0.98 ? "positive" : "neutral"
            }
            hint="完成 / (完成 + 不良)"
          />
          <Statistic
            label="計画比"
            value={
              <Delta
                value={totals.planVariance}
                format={(v) => `${nf(Math.abs(v))} 個`}
                tones={{ positive: "success", negative: "destructive", zero: "muted" }}
                labels={{ positive: "先行", negative: "遅れ", zero: "計画通り" }}
                showLabel
              />
            }
            hint={`計画 ${nf(order.plannedDoneByNow)} 個`}
          />
        </div>
      </section>

      {/* ── 稼働状況 + 進捗メーター ───────────────────────────────────────── */}
      <section aria-labelledby="status-heading" className="mt-6 grid gap-4 lg:grid-cols-3">
        <h2 id="status-heading" className="sr-only">
          稼働状況と進捗
        </h2>

        {/* 稼働率 gauge */}
        <Card>
          <CardHeader>
            <CardTitle as="h3" className="flex items-center gap-2 text-base">
              <IconChartBar className="h-4 w-4" aria-hidden="true" />
              稼働率 (OEE)
            </CardTitle>
            <CardDescription>実稼働時間 / 計画稼働時間</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col items-center gap-2">
            <GaugeChart
              value={Math.round(oee * 100)}
              min={0}
              max={100}
              color={oeeColor}
              label="稼働率"
              valueLabel={pf(oee, 0)}
              formatValue={(v) => `${v}%`}
              aria-label={`稼働率 ${pf(oee, 1)}（目標 85%）`}
            />
            <p className="text-xs text-muted-foreground">
              実稼働 {nf(order.actualRuntimeMin)} 分 / 計画 {nf(order.plannedRuntimeMin)} 分・目標 85%
            </p>
          </CardContent>
        </Card>

        {/* ライン状態 */}
        <Card>
          <CardHeader>
            <CardTitle as="h3" className="flex items-center gap-2 text-base">
              <LineIcon className="h-4 w-4" aria-hidden="true" />
              稼働状況 / ライン
            </CardTitle>
            <CardDescription>{order.line}</CardDescription>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="flex items-center gap-2">
              <Badge variant={LINE_STATUS_BADGE[order.lineStatus]} className="h-7 gap-1.5 px-3 text-sm">
                <LineIcon className="h-4 w-4" aria-hidden="true" />
                {LINE_STATUS_LABEL[order.lineStatus]}
              </Badge>
              <span className="text-sm text-muted-foreground">現工程: {curStep?.name ?? "—"}</span>
            </div>
            <fieldset>
              <legend className="mb-1.5 text-xs font-medium text-muted-foreground">
                ライン状態の変更
              </legend>
              <div className="flex flex-wrap gap-2">
                {(["running", "setup", "chokotei", "fault"] as LineStatus[]).map((ls) => {
                  const Ic = LINE_STATUS_ICON[ls];
                  const active = order.lineStatus === ls;
                  return (
                    <Button
                      key={ls}
                      size="sm"
                      variant={
                        active
                          ? ls === "fault"
                            ? "destructive"
                            : "primary"
                          : "outline"
                      }
                      aria-pressed={active}
                      onClick={() =>
                        setLineStatusByOrder((prev) => ({ ...prev, [orderId]: ls }))
                      }
                    >
                      <Ic className="h-4 w-4" aria-hidden="true" />
                      {LINE_STATUS_LABEL[ls]}
                    </Button>
                  );
                })}
              </div>
            </fieldset>
          </CardContent>
        </Card>

        {/* 進捗 + 良品率 meters */}
        <Card>
          <CardHeader>
            <CardTitle as="h3" className="text-base">
              全体進捗 / 良品率
            </CardTitle>
            <CardDescription>完成 {nf(totals.finished)} / 指示 {nf(totals.orderQty)}</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <Meter
              label="進捗率"
              value={totals.finished}
              max={totals.orderQty}
              tone="info"
              unit=" 個"
            />
            <Meter
              label="良品率"
              value={totals.yieldRate === null ? 0 : Math.round(totals.yieldRate * 1000) / 10}
              max={100}
              unit="%"
              tone={yieldTone}
              valueText={`良品率 ${pf(totals.yieldRate)}（目標 98%）`}
            />
            <div className="flex items-center justify-between text-sm">
              <span className="text-muted-foreground">不良率 (許容 {pf(order.defectRateCritical, 0)})</span>
              <ReferenceValue
                value={Math.round(defectRate * 1000) / 10}
                range={{
                  high: order.defectRateWarn * 100,
                  criticalHigh: order.defectRateCritical * 100,
                }}
                unit="%"
                format={(v) => v.toFixed(2)}
                labels={{ high: "注意", "critical-high": "超過", normal: "基準内" }}
                showLabel
              />
            </div>
          </CardContent>
        </Card>
      </section>

      {/* ── 工程ルート + 実績入力 + 不良集計 ──────────────────────────────── */}
      <section className="mt-6">
        <Tabs defaultValue="route">
          <TabsList>
            <TabsTrigger value="route">
              <IconRoute className="h-4 w-4" aria-hidden="true" />
              工程ルート
            </TabsTrigger>
            <TabsTrigger value="defects">
              <IconChartBar className="h-4 w-4" aria-hidden="true" />
              不良集計
            </TabsTrigger>
          </TabsList>

          {/* 工程ルート (centerpiece) */}
          <TabsContent value="route">
            <div className="grid gap-4 lg:grid-cols-3">
              <Card className="lg:col-span-2">
                <CardHeader>
                  <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                    <IconRoute className="h-5 w-5" aria-hidden="true" />
                    工程ルート / 進捗
                  </CardTitle>
                  <CardDescription>
                    材料投入 → 加工 → 組立 → 検査 → 梱包。現在の工程は強調表示。
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  <RouteStops
                    stops={routeStops}
                    statusLabels={ROUTE_STATUS_LABELS}
                    timeLabels={{ planned: "開始", actual: "完了" }}
                  />
                </CardContent>
              </Card>

              {/* 実績入力 for current process */}
              <Card>
                <CardHeader>
                  <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                    <IconClipboardCheck className="h-5 w-5" aria-hidden="true" />
                    実績入力
                  </CardTitle>
                  <CardDescription>
                    {order.status === "completed"
                      ? "この指図は完了しています。"
                      : `現工程: ${curStep?.name ?? "—"}（${curStep?.equipment ?? "—"}）`}
                  </CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  {order.status !== "completed" && curStep ? (
                    <>
                      <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-1.5">
                          <Label htmlFor="good-qty">良品数</Label>
                          <NumberInput
                            id="good-qty"
                            layout="stepper"
                            value={curStep.good}
                            min={0}
                            max={curStep.input || undefined}
                            onValueChange={(v) => updateCurrentStep({ good: v })}
                            aria-describedby="good-hint"
                          />
                          <p id="good-hint" className="text-xs text-muted-foreground">
                            投入 {nf(curStep.input)} 個まで
                          </p>
                        </div>
                        <div className="space-y-1.5">
                          <Label htmlFor="defect-qty">不良数</Label>
                          <NumberInput
                            id="defect-qty"
                            layout="stepper"
                            value={curStep.defect}
                            min={0}
                            max={curStep.input || undefined}
                            onValueChange={(v) => updateCurrentStep({ defect: v })}
                          />
                        </div>
                      </div>

                      <Separator />

                      <dl className="space-y-1.5 text-sm">
                        <div className="flex justify-between">
                          <dt className="text-muted-foreground">工程仕掛数</dt>
                          <dd className="font-medium tabular-nums">{nf(stepWip(curStep))} 個</dd>
                        </div>
                        <div className="flex justify-between">
                          <dt className="text-muted-foreground">工程良品率</dt>
                          <dd className="font-medium tabular-nums">{pf(stepYield(curStep))}</dd>
                        </div>
                        <div className="flex justify-between">
                          <dt className="text-muted-foreground">指図 完成数</dt>
                          <dd className="font-medium tabular-nums">{nf(totals.finished)} 個</dd>
                        </div>
                      </dl>

                      <Meter
                        label="工程の良品率"
                        size="inline"
                        value={stepYield(curStep) === null ? 0 : Math.round((stepYield(curStep) as number) * 100)}
                        max={100}
                        unit="%"
                        tone={
                          stepYield(curStep) === null
                            ? "muted"
                            : rateTone(stepYield(curStep) as number, 0.98, 0.95)
                        }
                      />

                      <div className="flex flex-wrap gap-2 pt-1">
                        <Button
                          variant="success"
                          onClick={() => setStepStatus(curIdx, "completed")}
                          disabled={curStep.status === "completed"}
                        >
                          <IconCheck className="h-4 w-4" />
                          工程完了
                        </Button>
                        <Button variant="outline">
                          <IconDeviceFloppy className="h-4 w-4" />
                          一時保存
                        </Button>
                      </div>
                    </>
                  ) : (
                    <div className="flex flex-col items-center gap-2 py-6 text-center">
                      <IconCircleCheck className="h-8 w-8 text-success-strong" aria-hidden="true" />
                      <p className="text-sm text-muted-foreground">
                        全工程完了。製造完了報告へ進めます。
                      </p>
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          </TabsContent>

          {/* 不良集計 (pareto-ish) */}
          <TabsContent value="defects">
            <Card>
              <CardHeader className="sm:flex-row sm:items-start sm:justify-between">
                <div className="space-y-1.5">
                  <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                    <IconChartBar className="h-5 w-5" aria-hidden="true" />
                    不良集計
                  </CardTitle>
                  <CardDescription>
                    不良項目別の発生件数（多い順）。合計 {nf(reasonSum)} 件。
                  </CardDescription>
                </div>
                <Badge
                  variant={defectOver ? "destructive" : defectWarn ? "warning" : "success"}
                  className="h-7 gap-1.5 px-3 text-sm"
                >
                  {defectOver || defectWarn ? (
                    <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                  ) : (
                    <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                  )}
                  不良率 {pf(defectRate, 2)}
                </Badge>
              </CardHeader>
              <CardContent>
                {defectsSorted.length === 0 ? (
                  <div className="flex flex-col items-center gap-2 py-8 text-center">
                    <IconCircleCheck className="h-8 w-8 text-success-strong" aria-hidden="true" />
                    <p className="text-sm text-muted-foreground">不良の登録はありません。</p>
                  </div>
                ) : (
                  <>
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>不良項目</TableHead>
                          <TableHead className="text-right">件数</TableHead>
                          <TableHead className="w-[34%]">構成比</TableHead>
                          <TableHead className="text-right">累計比</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {(() => {
                          let cumulative = 0;
                          return defectsSorted.map((d) => {
                            cumulative += d.count;
                            const share = reasonSum > 0 ? d.count / reasonSum : 0;
                            const cum = reasonSum > 0 ? cumulative / reasonSum : 0;
                            return (
                              <TableRow key={d.code}>
                                <TableCell className="font-medium">
                                  {d.label}
                                  <span className="ml-1.5 text-xs text-muted-foreground">{d.code}</span>
                                </TableCell>
                                <TableCell className="text-right tabular-nums">{nf(d.count)}</TableCell>
                                <TableCell>
                                  <Meter
                                    size="inline"
                                    value={d.count}
                                    max={defectMax}
                                    tone="warning"
                                    label={`${d.label} 構成比`}
                                    valueText={`${d.label} ${pf(share)}`}
                                    showValue={false}
                                  />
                                </TableCell>
                                <TableCell className="text-right tabular-nums text-muted-foreground">
                                  {pf(cum)}
                                </TableCell>
                              </TableRow>
                            );
                          });
                        })()}
                        <TableRow className="border-t-2">
                          <TableCell className="font-semibold">合計</TableCell>
                          <TableCell className="text-right font-semibold tabular-nums">
                            {nf(reasonSum)}
                          </TableCell>
                          <TableCell colSpan={2} className="text-right text-xs text-muted-foreground">
                            不良数(指図) {nf(totals.totalDefect)} と一致
                          </TableCell>
                        </TableRow>
                      </TableBody>
                    </Table>
                    <div className="mt-3 flex flex-wrap gap-2">
                      <Button variant="outline" size="sm">
                        <IconAlertTriangle className="h-4 w-4" />
                        不良を登録
                      </Button>
                    </div>
                  </>
                )}
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </section>

      {/* ── 主アクション ─────────────────────────────────────────────────── */}
      <section aria-labelledby="actions-heading" className="mt-6">
        <h2 id="actions-heading" className="sr-only">
          指図アクション
        </h2>
        <Card>
          <CardContent className="flex flex-wrap items-center gap-2 p-4">
            <Button variant="primary" disabled={order.status !== "in-progress" || defectOver}>
              <IconClipboardCheck className="h-4 w-4" />
              製造完了報告
            </Button>
            <Button variant="outline">
              <IconClipboardList className="h-4 w-4" />
              作業指示書を印刷
            </Button>
            <Button variant="outline">
              <IconReportAnalytics className="h-4 w-4" />
              進捗レポート
            </Button>
            {defectOver && (
              <span className="ml-auto inline-flex items-center gap-1.5 text-sm text-destructive">
                <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                不良率超過のため完了報告はブロック中
              </span>
            )}
          </CardContent>
        </Card>
      </section>
    </main>
  );
}
